import{_ as a,o as i,c as o,a2 as t}from"./chunks/framework.OWFDNrRT.js";const u=JSON.parse('{"title":"KooshaPari Project Semantics","description":"","frontmatter":{},"headers":[],"relativePath":"reference/kooshapari-project-semantics.md","filePath":"reference/kooshapari-project-semantics.md","lastUpdated":1773460793000}'),r={name:"reference/kooshapari-project-semantics.md"};function s(n,e,c,l,d,h){return i(),o("div",null,[...e[0]||(e[0]=[t('<h1 id="kooshapari-project-semantics" tabindex="-1">KooshaPari Project Semantics <a class="header-anchor" href="#kooshapari-project-semantics" aria-label="Permalink to &quot;KooshaPari Project Semantics&quot;">​</a></h1><p>This document captures the release and governance semantics that should stay consistent across KooshaPari projects, plus the semantics that are intentionally Dino-specific.</p><h2 id="shared-kooshapari-semantics" tabindex="-1">Shared KooshaPari semantics <a class="header-anchor" href="#shared-kooshapari-semantics" aria-label="Permalink to &quot;Shared KooshaPari semantics&quot;">​</a></h2><p>These are the patterns already visible across active KooshaPari repositories such as <code>Dino</code>, <code>cliproxyapi-plusplus</code>, <code>thegent</code>, <code>portage</code>, and <code>helios-cli</code>.</p><h3 id="_1-canonical-repo-governance-files" tabindex="-1">1. Canonical repo governance files <a class="header-anchor" href="#_1-canonical-repo-governance-files" aria-label="Permalink to &quot;1. Canonical repo governance files&quot;">​</a></h3><p>Every active public project should carry:</p><ul><li><code>README.md</code></li><li><code>CHANGELOG.md</code></li><li><code>SECURITY.md</code></li><li><code>.github/</code></li><li><code>docs/</code></li></ul><p>When a repo is intended for sustained maintenance, also add:</p><ul><li><code>.github/CODEOWNERS</code></li><li><code>CONTRIBUTING.md</code></li><li><code>RELEASING.md</code></li></ul><p>For agent-first or autonomously-maintained repositories, also add:</p><ul><li><code>AGENTS.md</code> (agent governance and autonomous workflow guidelines)</li></ul><h3 id="_2-release-semantics" tabindex="-1">2. Release semantics <a class="header-anchor" href="#_2-release-semantics" aria-label="Permalink to &quot;2. Release semantics&quot;">​</a></h3><p>Use one public release language across repos:</p><ul><li>SemVer tags in the form <code>vX.Y.Z</code></li><li>Keep a Changelog with <code>[Unreleased]</code></li><li>a machine-readable version signal when the repo is not purely a language/toolchain implementation (i.e., when it includes application or library code beyond just compiler/interpreter source)</li><li>release artifacts with checksums when binaries or packages are published</li></ul><h3 id="_3-ci-and-security-semantics" tabindex="-1">3. CI and security semantics <a class="header-anchor" href="#_3-ci-and-security-semantics" aria-label="Permalink to &quot;3. CI and security semantics&quot;">​</a></h3><p>Prefer the same formal controls across repos:</p><ul><li>pinned GitHub Actions</li><li>Dependabot</li><li>security policy and supported-version statement</li><li>Codecov or equivalent coverage reporting with repo config</li><li>SBOM and supply-chain attestations where artifacts are distributed</li><li>explicit policy-gate style workflow for governance checks</li></ul><h3 id="_4-ownership-semantics" tabindex="-1">4. Ownership semantics <a class="header-anchor" href="#_4-ownership-semantics" aria-label="Permalink to &quot;4. Ownership semantics&quot;">​</a></h3><p>Review routing should be explicit rather than tribal:</p><ul><li><code>.github/CODEOWNERS</code> for ownership</li><li>pull request template for verification</li><li>release checklist for artifact review</li></ul><h3 id="_5-agent-and-automation-semantics" tabindex="-1">5. Agent and automation semantics <a class="header-anchor" href="#_5-agent-and-automation-semantics" aria-label="Permalink to &quot;5. Agent and automation semantics&quot;">​</a></h3><p>KooshaPari projects increasingly assume autonomous or semi-autonomous engineering workflows. Shared semantics should therefore include:</p><ul><li>machine-parseable CLI output where practical</li><li>documented governance for changelog/version/release behavior</li><li>ADRs or equivalent decision records for architectural choices</li><li>narrow policy gates rather than informal review-only enforcement</li></ul><h2 id="dino-specific-semantics" tabindex="-1">Dino-specific semantics <a class="header-anchor" href="#dino-specific-semantics" aria-label="Permalink to &quot;Dino-specific semantics&quot;">​</a></h2><p>These should stay explicit in Dino even if they do not apply to every KooshaPari repo.</p><h3 id="_1-schema-first-mod-contracts" tabindex="-1">1. Schema-first mod contracts <a class="header-anchor" href="#_1-schema-first-mod-contracts" aria-label="Permalink to &quot;1. Schema-first mod contracts&quot;">​</a></h3><p>In Dino, schemas are part of the product contract, not just validation helpers.</p><h3 id="_2-layered-runtime-sdk-domains-tools-and-packs-split" tabindex="-1">2. Layered Runtime, SDK, Domains, Tools, and Packs split <a class="header-anchor" href="#_2-layered-runtime-sdk-domains-tools-and-packs-split" aria-label="Permalink to &quot;2. Layered Runtime, SDK, Domains, Tools, and Packs split&quot;">​</a></h3><p>The Runtime, SDK, Domains, Tools, and Packs separation is central to Dino’s architecture and should remain more explicit than in standard app repos.</p><h3 id="_3-pack-compatibility-and-framework-versioning" tabindex="-1">3. Pack compatibility and framework versioning <a class="header-anchor" href="#_3-pack-compatibility-and-framework-versioning" aria-label="Permalink to &quot;3. Pack compatibility and framework versioning&quot;">​</a></h3><p>Pack manifests, framework compatibility ranges, and runtime bridges are first-class release concerns in Dino.</p><h3 id="_4-agent-first-tool-output" tabindex="-1">4. Agent-first tool output <a class="header-anchor" href="#_4-agent-first-tool-output" aria-label="Permalink to &quot;4. Agent-first tool output&quot;">​</a></h3><p>Dino’s toolchain should continue to prefer machine-readable output because the repo is intentionally agent-operated.</p><h2 id="what-dino-should-export-back-into-other-kooshapari-repos" tabindex="-1">What Dino should export back into other KooshaPari repos <a class="header-anchor" href="#what-dino-should-export-back-into-other-kooshapari-repos" aria-label="Permalink to &quot;What Dino should export back into other KooshaPari repos&quot;">​</a></h2><p>Dino has a few strong patterns worth carrying outward:</p><ul><li>ADR discipline for architecture decisions</li><li>explicit release and changelog governance</li><li>schema/contract-centric thinking</li><li>artifact checksum expectations for shipped binaries</li></ul><h2 id="what-dino-should-import-from-the-wider-kooshapari-portfolio" tabindex="-1">What Dino should import from the wider KooshaPari portfolio <a class="header-anchor" href="#what-dino-should-import-from-the-wider-kooshapari-portfolio" aria-label="Permalink to &quot;What Dino should import from the wider KooshaPari portfolio&quot;">​</a></h2><p>Dino should continue adopting the stronger portfolio-wide governance posture:</p><ul><li>CODEOWNERS everywhere a repo is actively maintained</li><li>standardized release semantics</li><li>consistent coverage reporting policy</li><li>explicit security reporting guidance</li></ul>',39)])])}const m=a(r,[["render",s]]);export{u as __pageData,m as default};
